	wp_fusion()->crm->track_event( 'Completed ' . $label, $last_item->post_title );

	// Quizzes

	if ( isset( $data['quiz'] ) ) {

		if ( true == $data['pass'] ) {
			wp_fusion()->crm->track_event( 'Passed quiz' );
		} else {
			wp_fusion()->crm->track_event( 'Failed quiz' );
		}
	}

}

