	if ( empty( $widget_tags ) ) {
		return $can_access;
	}

	$user_tags = wp_fusion()->user->get_tags();

	$result = array_intersect( $widget_tags, $user_tags );

	if ( count( $result ) == count( $widget_tags ) ) {
