	$roles = array( 'deals_contributor' );
	$user = get_userdata( $user_id );

	if ( affwp_is_affiliate( $user_id ) ) {
		return true;
	}

	foreach ( $roles as $role ) {
		if ( 'deals_contributor' === $user->role ) {
			return true;
		}
	}

	return false;
}

