			} catch ( Exception $e ) {
				wpf_log( 'error', $user_id, 'Error creating tag for field value ' . $user_meta['custom_field_key'] . ': ' . $e->getMessage() );
			}

			if ( ! is_wp_error( $tag_id ) ) {
				wp_fusion()->user->apply_tags( array( $tag_id ), $user_id );
			}
		}
	}

}

